"use strict";module.exports={meta:{type:"suggestion",docs:{description:"Disallow equal signs explicitly at the beginning of regular expressions",recommended:!1,frozen:!0,url:"https://eslint.org/docs/latest/rules/no-div-regex"},fixable:"code",schema:[],messages:{unexpected:"A regular expression literal can be confused with '/='."}},create(e){const s=e.sourceCode;return{Literal(r){const t=s.getFirstToken(r);"RegularExpression"===t.type&&"="===t.value[1]&&e.report({node:r,messageId:"unexpected",fix:e=>e.replaceTextRange([t.range[0]+1,t.range[0]+2],"[=]")})}}}};